    .frame(maxWidth: .infinity, alignment: .center)
    .frame(height: 56)
    .background(Color.white.edgesIgnoringSafeArea(.bottom))
    .sheet(
      item: $store.scope(state: \.upgradeInterstitial, action: \.upgradeInterstitial)
    ) { store in
      UpgradeInterstitialView(store: store)
    }
  }
}

