import AudioPlayerClient
import ComposableArchitecture
import SharedModels
import TcaHelpers

extension Reducer {
  public func selectionSounds(
    contains: @escaping (State, String) -> Bool,
    hasBeenPlayed: @escaping (State, String) -> Bool,
    puzzle: @escaping (State) -> Puzzle,
    selectedWord: @escaping (State) -> [IndexedCubeFace]
  ) -> SelectionSounds<Self> {
    SelectionSounds(
      base: self,
      contains: contains,
      hasBeenPlayed: hasBeenPlayed,
      puzzle: puzzle,
      selectedWord: selectedWord
    )
  }
}

@Reducer
public struct SelectionSounds<Base: Reducer> {
  let base: Base
  let contains: (Base.State, String) -> Bool
  let hasBeenPlayed: (Base.State, String) -> Bool
  let puzzle: (Base.State) -> Puzzle
  let selectedWord: (Base.State) -> [IndexedCubeFace]

  @Dependency(\.audioPlayer.play) var playSound

  public var body: some ReducerOf<Base> {
    self.base.onChange(of: self.selectedWord) { previousSelection, selection in
      Reduce { state, action in
        .run { [state] _ in
          if let noteIndex = noteIndex(
            selectedWord: selection,
            cubes: self.puzzle(state),
            notes: AudioPlayerClient.Sound.allNotes
          ) {
            await self.playSound(AudioPlayerClient.Sound.allNotes[noteIndex])
          }

          let selectedWordString = self.puzzle(state).string(from: selection)
          if !hasBeenPlayed(state, selectedWordString)
            && contains(state, selectedWordString)
          {
            let validCount = selectedWordString
              .indices
              .dropFirst(2)
              .reduce(into: 0) { count, index in
                count +=
                  contains(state, String(selectedWordString[...index]))
                  ? 1
                  : 0
              }
            if validCount > 0 {
              await self.playSound(.validWord(level: validCount))
            }
          }
        }
      }
    }
  }
}

private func noteIndex(
  selectedWord: [IndexedCubeFace],
  cubes: Puzzle,
  notes: [AudioPlayerClient.Sound]
) -> Int? {
  guard
    let firstFace = selectedWord.first,
    let firstAscii = cubes[firstFace].letter.first?.utf8.first
  else { return nil }

  let firstIndex = Int(
    (firstAscii - .init(ascii: "A"))
      .quotientAndRemainder(dividingBy: .init(ascii: "O") - .init(ascii: "A"))
      .remainder
  )

  return min(
    firstIndex + selectedWord.count - 1,
    notes.count - 1
  )
}

import SwiftUI

public enum NavPresentationStyle {
  case modal
  case navigation
}

extension View {
  public func navigationStyle<Title: View, Trailing: View>(
    backgroundColor: Color = .adaptiveWhite,
    foregroundColor: Color = .adaptiveBlack,
    title: Title,
    navPresentationStyle: NavPresentationStyle = .navigation,
    trailing: Trailing,
    onDismiss: @escaping () -> Void = {}
  ) -> some View {
    NavigationBar(
      backgroundColor: backgroundColor,
      content: self,
      foregroundColor: foregroundColor,
      navPresentationStyle: navPresentationStyle,
      onDismiss: onDismiss,
      title: title,
      trailing: trailing
    )
  }

  public func navigationStyle<Title: View>(
    backgroundColor: Color = .adaptiveWhite,
    foregroundColor: Color = .adaptiveBlack,
    title: Title,
    navPresentationStyle: NavPresentationStyle = .navigation,
    onDismiss: @escaping () -> Void = {}
  ) -> some View {
    self.navigationStyle(
      backgroundColor: backgroundColor,
      foregroundColor: foregroundColor,
      title: title,
      navPresentationStyle: navPresentationStyle,
      trailing: EmptyView(),
      onDismiss: onDismiss
    )
  }
}

private struct NavigationBar<Title: View, Content: View, Trailing: View>: View {
  let backgroundColor: Color
  let content: Content
  let foregroundColor: Color
  let navPresentationStyle: NavPresentationStyle
  let onDismiss: () -> Void
  @Environment(\.presentationMode) @Binding var presentationMode
  let title: Title
  let trailing: Trailing

  var body: some View {
    VStack {
      ZStack {
        self.title.adaptiveFont(.matterMedium, size: 14)
        HStack {
          if self.navPresentationStyle == .navigation {
            Button(action: self.dismiss) {
              Image(systemName: "arrow.left")
            }
          }
          Spacer()
          if self.navPresentationStyle == .modal {
            Button(action: self.dismiss) {
              Text("Done")
                .adaptiveFont(.matterMedium, size: 14)
            }
          } else {
            self.trailing
          }
        }
      }
      .padding()

      self.content
    }
    .background(self.backgroundColor.ignoresSafeArea())
    .foregroundColor(self.foregroundColor)
    .navigationBarHidden(true)
  }

  func dismiss() {
    self.onDismiss()
    self.presentationMode.dismiss()
  }
}

