import APNS
import Vapor

public extension Request {
    var apns: APNSwiftClient {
        TestableAPNS(request: self)
    }

    struct TestableAPNS {
        let request: Request
    }
}

extension Request.TestableAPNS: APNSwiftClient {
    private var isTesting: Bool {
        request.application.environment == .testing
    }

    struct PendingSend {
        var promise: EventLoopPromise<Void>
        var payload: ByteBuffer
        var pushType: APNSwiftConnection.PushType
        var deviceToken: String
        var expiration: Date?
        var priority: Int?
        var collapseIdentifier: String?
        var topic: String?
        var apnsID: UUID?
    }

    static var pendingSendHandler: (PendingSend) -> Void = { _ in }

    public var logger: Logger? {
        request.logger
    }

    public var eventLoop: EventLoop {
        request.eventLoop
    }

    public func send(
        rawBytes payload: ByteBuffer,
        pushType: APNSwiftConnection.PushType,
        to deviceToken: String,
        expiration: Date?,
        priority: Int?,
        collapseIdentifier: String?,
        topic: String?,
        logger: Logger?,
        apnsID: UUID? = nil
    ) -> EventLoopFuture<Void> {
        if isTesting {
            let promise = request.eventLoop.makePromise(of: Void.self)
            Self.pendingSendHandler(.init(
                promise: promise,
                payload: payload,
                pushType: pushType,
                deviceToken: deviceToken,
                expiration: expiration,
                priority: priority,
                collapseIdentifier: collapseIdentifier,
                topic: topic,
                apnsID: apnsID
            ))
            return promise.futureResult
        } else {
            return request.application.apns.pool.withConnection(
                logger: logger,
                on: eventLoop
            ) {
                $0.send(
                    rawBytes: payload,
                    pushType: pushType,
                    to: deviceToken,
                    expiration: expiration,
                    priority: priority,
                    collapseIdentifier: collapseIdentifier,
                    topic: topic,
                    logger: logger,
                    apnsID: apnsID
                )
            }
        }
    }
}

import Foundation
import HAKit
import PromiseKit

final class FocusSensorUpdateSignaler: BaseSensorUpdateSignaler, SensorProviderUpdateSignaler {
    var cancellable: HACancellable?
    private let signal: () -> Void

    init(signal: @escaping () -> Void) {
        self.signal = signal
        super.init(relatedSensorsIds: [
            .focus,
        ])
    }

    deinit {
        cancellable?.cancel()
    }

    override func observe() {
        super.observe()
        guard !isObserving else { return }
        cancellable = Current.focusStatus.trigger.observe { [weak self] _ in
            #if os(watchOS)
            self?.signal()
            #else
            // this means that we will double-update the focus sensor if the app is running
            // this feels less likely to happen, but allows us to keep the in-app visual state right
            if Current.isForegroundApp() {
                self?.signal()
            }
            #endif
        }
        isObserving = true

        #if DEBUG
        notifyObservation?()
        #endif
    }

    override func stopObserving() {
        super.stopObserving()
        guard isObserving else { return }
        cancellable?.cancel()
        isObserving = false
    }
}

final class FocusSensor: SensorProvider {
    public enum FocusError: Error, Equatable {
        case unauthorized
        case unavailable
    }

    let request: SensorProviderRequest
    init(request: SensorProviderRequest) {
        self.request = request
    }

    func sensors() -> Promise<[WebhookSensor]> {
        guard Current.focusStatus.isAvailable() else {
            return .init(error: FocusError.unavailable)
        }

        guard Current.focusStatus.authorizationStatus() == .authorized else {
            return .init(error: FocusError.unauthorized)
        }

        let focusState = Current.focusStatus.status()
        var sensors = [WebhookSensor]()

        if let isFocused = focusState.isFocused {
            sensors.append(with(WebhookSensor(
                name: "Focus",
                uniqueID: WebhookSensorId.focus.rawValue,
                icon: "mdi:moon-waning-crescent",
                state: isFocused
            )) {
                $0.Type = "binary_sensor"
            })
        }

        // Set up our observer
        let _: FocusSensorUpdateSignaler = request.dependencies.updateSignaler(for: self)

        return .value(sensors)
    }
}

import Intents
import PromiseKit

public class FocusStateTrigger: UserDefaultsValueSync<Date> {
    init() {
        super.init(settingsKey: "FocusStateTriggerKey")
    }
}

public class FocusStatusWrapper {
    private(set) lazy var trigger = FocusStateTrigger()

    public enum AuthorizationStatus: Equatable {
        case notDetermined
        case restricted
        case denied
        case authorized

        init(authorizationStatus: INFocusStatusAuthorizationStatus) {
            switch authorizationStatus {
            case .notDetermined:
                self = .notDetermined
            case .restricted:
                self = .restricted
            case .denied:
                self = .denied
            case .authorized:
                self = .authorized
            @unknown default:
                self = .denied
            }
        }
    }

    private var lastStatus: Status? {
        willSet {
            precondition(Current.isAppExtension)
        }
    }

    public lazy var isAvailable: () -> Bool = { [weak self] in
        if Current.isAppExtension {
            return self?.lastStatus != nil
        } else {
            return true
        }
    }

    public var authorizationStatus: () -> AuthorizationStatus = {
        .init(authorizationStatus: INFocusStatusCenter.default.authorizationStatus)
    }

    public var requestAuthorization: () -> Guarantee<AuthorizationStatus> = {
        let (promise, seal) = Guarantee<AuthorizationStatus>.pending()

        INFocusStatusCenter.default.requestAuthorization { result in
            seal(.init(authorizationStatus: result))
        }

        return promise
    }

    public struct Status: Equatable {
        public var isFocused: Bool?

        public init(focusStatus: INFocusStatus) {
            self.init(
                isFocused: focusStatus.isFocused
            )
        }

        public init(isFocused: Bool?) {
            self.isFocused = isFocused
        }
    }

    public func update(fromReceived status: INFocusStatus?) {
        precondition(Current.isAppExtension)
        lastStatus = status.flatMap { Status(focusStatus: $0) }
        trigger.value = Current.date()
    }

    public lazy var status: () -> Status = { [weak self] in
        if Current.isAppExtension, let lastStatus = self?.lastStatus {
            return lastStatus
        } else {
            return .init(focusStatus: INFocusStatusCenter.default.focusStatus)
        }
    }
}

import ActiveGamesFeature
import ComposableArchitecture

@Reducer
public struct ActiveGamesTray {
  @Dependency(\.fileClient) var fileClient
  @Dependency(\.gameCenter) var gameCenter
  @Dependency(\.mainRunLoop.now.date) var now

  public var body: some ReducerOf<Game> {
    Reduce { state, action in
      switch action {
      case .cancelButtonTapped,
        .confirmRemoveCube,
        .doubleTap,
        .destination(.presented(.bottomMenu(.confirmRemoveCube))),
        .destination(.presented(.bottomMenu(.endGameButtonTapped))),
        .destination(.presented(.bottomMenu(.forfeitGameButtonTapped))),
        .menuButtonTapped,
        .pan,
        .submitButtonTapped,
        .tap,
        .wordSubmitButton:

        state.isTrayVisible = false
        return .none

      case .activeGames,
        .delayedShowUpgradeInterstitial,
        .destination(.presented(.bottomMenu(.exitButtonTapped))),
        .destination(.presented(.bottomMenu(.settingsButtonTapped))),
        .destination,
        .gameCenter,
        .gameLoaded,
        .lowPowerModeChanged,
        .matchesLoaded(.failure),
        .savedGamesLoaded(.failure),
        .timerTick,
        .userSettingsUpdated:

        return .none

      case let .matchesLoaded(.success(matches)):
        state.activeGames.turnBasedMatches = matches.activeMatches(
          for: self.gameCenter.localPlayer.localPlayer(),
          at: self.now
        )
        return .none

      case .task:
        return self.activeGameEffects

      case let .savedGamesLoaded(.success(savedGames)):
        state.activeGames.savedGames = savedGames
        return .none

      case .trayButtonTapped:
        guard state.isTrayAvailable else { return .none }
        state.isTrayVisible.toggle()
        return state.isTrayVisible ? self.activeGameEffects : .none
      }
    }
  }

  var activeGameEffects: EffectOf<Self> {
    .run { send in
      await withThrowingTaskGroup(of: Void.self) { group in
        group.addTask {
          await send(
            .matchesLoaded(
              Result { try await self.gameCenter.turnBasedMatch.loadMatches() }
            ),
            animation: .default
          )
        }

        group.addTask {
          await send(
            .savedGamesLoaded(
              Result { try await self.fileClient.loadSavedGames() }
            ),
            animation: .default
          )
        }
      }
    }
  }
}

import PackagePlugin

protocol CommandContext {
    var tool: String { get throws }

    var cacheDirectory: String { get }

    var workingDirectory: String { get }

    var unitName: String { get }

    var subUnitName: String { get }

    func targets(named names: [String]) throws -> [(paths: [String], name: String)]
}

extension PluginContext: CommandContext {
    var tool: String {
        get throws {
            try tool(named: "swiftlint").path.string
        }
    }

    var cacheDirectory: String {
        pluginWorkDirectory.string
    }

    var workingDirectory: String {
        package.directory.string
    }

    var unitName: String {
        "package"
    }

    var subUnitName: String {
        "module"
    }

    func targets(named names: [String]) throws -> [(paths: [String], name: String)] {
        let targets = names.isEmpty
            ? package.targets
            : try package.targets(named: names)
        return targets.compactMap { target in
            guard let target = target.sourceModule else {
                Diagnostics.warning("Target '\(target.name)' is not a source module; skipping it")
                return nil
            }
            // Packages have a 1-to-1 mapping between targets and directories.
            return (paths: [target.directory.string], name: target.name)
        }
    }
}

#if canImport(XcodeProjectPlugin)

import XcodeProjectPlugin

extension XcodePluginContext: CommandContext {
    var tool: String {
        get throws {
            try tool(named: "swiftlint").path.string
        }
    }

    var cacheDirectory: String {
        pluginWorkDirectory.string
    }

    var workingDirectory: String {
        xcodeProject.directory.string
    }

    var unitName: String {
        "project"
    }

    var subUnitName: String {
        "target"
    }

    func targets(named names: [String]) -> [(paths: [String], name: String)] {
        if names.isEmpty {
            return [(paths: [xcodeProject.directory.string], name: xcodeProject.displayName)]
        }
        return xcodeProject.targets
            .filter { names.contains($0.displayName) }
            .map { (paths: $0.inputFiles.map(\.path.string).filter { $0.hasSuffix(".swift") }, name: $0.displayName) }
    }
}

#endif
